     5→# React
     6→
     7→> A JavaScript library for building user interfaces with a component-based architecture.
     8→
     9→---
    10→
    11→## Overview
    12→
    13→React is a declarative, component-based library for building UIs:
    14→- **Component Model**: Encapsulated, reusable UI building blocks
    15→- **Virtual DOM**: Efficient DOM updates through reconciliation
    16→- **Unidirectional Data Flow**: Predictable state management
    17→- **Hooks**: Function-based state and lifecycle management
    18→- **Ecosystem**: Rich tooling and community support
    19→
    20→---
    21→
    22→## Why React
    23→
    24→| Benefit | Description |
    25→|---------|-------------|
    26→| Component Reuse | Build once, use everywhere |
    27→| Declarative | Describe UI, React handles updates |
    28→| Learn Once | Write web, mobile (React Native), desktop |
    29→| Large Ecosystem | Libraries for every need |
    30→| Industry Standard | Most in-demand frontend skill |
    31→
    32→---
    33→
    34→## Core Concepts
    35→
    36→### Components
    37→
    38→```tsx
    39→// Function component (modern standard)
    40→interface UserCardProps {
    41→  name: string;
    42→  email: string;
    43→  onSelect?: () => void;
    44→}
    45→
    46→export function UserCard({ name, email, onSelect }: UserCardProps) {
    47→  return (
    48→    <div className="user-card" onClick={onSelect}>
    49→      <h3>{name}</h3>
    50→      <p>{email}</p>
    51→    </div>
    52→  );
    53→}
    54→
    55→// Usage
    56→<UserCard name="John" email="john@example.com" />
    57→```
    58→
    59→### JSX
    60→
    61→```tsx
    62→// JSX is JavaScript + XML syntax
    63→const element = <h1>Hello, {user.name}!</h1>;
    64→
    65→// Compiles to
    66→const element = React.createElement('h1', null, `Hello, ${user.name}!`);
    67→
    68→// Conditional rendering
    69→{isLoggedIn && <WelcomeMessage />}
    70→{isAdmin ? <AdminPanel /> : <UserPanel />}
    71→
    72→// Lists with keys
    73→{items.map(item => (
    74→  <ListItem key={item.id} item={item} />
    75→))}
    76→```
    77→
    78→---
    79→
    80→## Hooks
    81→
    82→### useState
    83→
    84→```tsx
    85→import { useState } from "react";
    86→
    87→function Counter() {
    88→  const [count, setCount] = useState(0);
    89→
    90→  return (
    91→    <div>
    92→      <p>Count: {count}</p>
    93→      <button onClick={() => setCount(count + 1)}>+</button>
    94→      <button onClick={() => setCount(c => c - 1)}>-</button>
    95→    </div>
    96→  );
    97→}
    98→```
    99→
   100→### useEffect
   101→
   102→```tsx
   103→import { useEffect, useState } from "react";
   104→
   105→function UserProfile({ userId }: { userId: string }) {
   106→  const [user, setUser] = useState<User | null>(null);
   107→
   108→  useEffect(() => {
   109→    let cancelled = false;
   110→
   111→    async function fetchUser() {
   112→      const response = await fetch(`/api/users/${userId}`);
   113→      const data = await response.json();
   114→      if (!cancelled) {
   115→        setUser(data);
   116→      }
   117→    }
   118→
   119→    fetchUser();
   120→
   121→    // Cleanup function
   122→    return () => {
   123→      cancelled = true;
   124→    };
   125→  }, [userId]); // Dependency array
   126→
   127→  if (!user) return <Loading />;
   128→  return <div>{user.name}</div>;
   129→}
   130→```
   131→
   132→### useCallback & useMemo
   133→
   134→```tsx
   135→import { useCallback, useMemo } from "react";
   136→
   137→function ExpensiveList({ items, filter }: Props) {
   138→  // Memoize expensive computation
   139→  const filteredItems = useMemo(
   140→    () => items.filter(item => item.name.includes(filter)),
   141→    [items, filter]
   142→  );
   143→
   144→  // Memoize callback to prevent child re-renders
   145→  const handleSelect = useCallback((id: string) => {
   146→    console.log("Selected:", id);
   147→  }, []);
   148→
   149→  return (
   150→    <ul>
   151→      {filteredItems.map(item => (
   152→        <ListItem
   153→          key={item.id}
   154→          item={item}
   155→          onSelect={handleSelect}
   156→        />
   157→      ))}
   158→    </ul>
   159→  );
   160→}
   161→```
   162→
   163→### useRef
   164→
   165→```tsx
   166→import { useRef, useEffect } from "react";
   167→
   168→function TextInput() {
   169→  const inputRef = useRef<HTMLInputElement>(null);
   170→
   171→  useEffect(() => {
   172→    // Focus on mount
   173→    inputRef.current?.focus();
   174→  }, []);
   175→
   176→  return <input ref={inputRef} type="text" />;
   177→}
   178→
   179→// Store mutable value without re-render
   180→function Timer() {
   181→  const intervalRef = useRef<number | null>(null);
   182→
   183→  const start = () => {
   184→    intervalRef.current = window.setInterval(() => {
   185→      console.log("tick");
   186→    }, 1000);
   187→  };
   188→
   189→  const stop = () => {
   190→    if (intervalRef.current) {
   191→      clearInterval(intervalRef.current);
   192→    }
   193→  };
   194→
   195→  return (
   196→    <>
   197→      <button onClick={start}>Start</button>
   198→      <button onClick={stop}>Stop</button>
   199→    </>
   200→  );
   201→}
   202→```
   203→
   204→### useContext
   205→
   206→```tsx
   207→import { createContext, useContext, useState, ReactNode } from "react";
   208→
   209→// Create context
   210→interface ThemeContextType {
   211→  theme: "light" | "dark";
   212→  toggle: () => void;
   213→}
   214→
   215→const ThemeContext = createContext<ThemeContextType | null>(null);
   216→
   217→// Provider component
   218→function ThemeProvider({ children }: { children: ReactNode }) {
   219→  const [theme, setTheme] = useState<"light" | "dark">("light");
   220→
   221→  const toggle = () => setTheme(t => t === "light" ? "dark" : "light");
   222→
   223→  return (
   224→    <ThemeContext.Provider value={{ theme, toggle }}>
   225→      {children}
   226→    </ThemeContext.Provider>
   227→  );
   228→}
   229→
   230→// Custom hook for consuming
   231→function useTheme() {
   232→  const context = useContext(ThemeContext);
   233→  if (!context) {
   234→    throw new Error("useTheme must be used within ThemeProvider");
   235→  }
   236→  return context;
   237→}
   238→
   239→// Usage
   240→function ThemedButton() {
   241→  const { theme, toggle } = useTheme();
   242→  return (
   243→    <button
   244→      className={theme === "dark" ? "bg-black" : "bg-white"}
   245→      onClick={toggle}
   246→    >
   247→      Toggle Theme
   248→    </button>
   249→  );
   250→}
   251→```
   252→
   253→### useReducer
   254→
   255→```tsx
   256→import { useReducer } from "react";
   257→
   258→interface State {
   259→  count: number;
   260→  error: string | null;
   261→}
   262→
   263→type Action =
   264→  | { type: "increment" }
   265→  | { type: "decrement" }
   266→  | { type: "reset" }
   267→  | { type: "error"; message: string };
   268→
   269→function reducer(state: State, action: Action): State {
   270→  switch (action.type) {
   271→    case "increment":
   272→      return { ...state, count: state.count + 1, error: null };
   273→    case "decrement":
   274→      return { ...state, count: state.count - 1, error: null };
   275→    case "reset":
   276→      return { count: 0, error: null };
   277→    case "error":
   278→      return { ...state, error: action.message };
   279→    default:
   280→      return state;
   281→  }
   282→}
   283→
   284→function Counter() {
   285→  const [state, dispatch] = useReducer(reducer, { count: 0, error: null });
   286→
   287→  return (
   288→    <div>
   289→      <p>Count: {state.count}</p>
   290→      {state.error && <p className="error">{state.error}</p>}
   291→      <button onClick={() => dispatch({ type: "increment" })}>+</button>
   292→      <button onClick={() => dispatch({ type: "decrement" })}>-</button>
   293→      <button onClick={() => dispatch({ type: "reset" })}>Reset</button>
   294→    </div>
   295→  );
   296→}
   297→```
