   299→---
   300→
   301→## React 19 Features
   302→
   303→### Actions (Form Handling)
   304→
   305→```tsx
   306→// Server action pattern (with Next.js)
   307→async function submitForm(formData: FormData) {
   308→  "use server";
   309→  const name = formData.get("name");
   310→  await saveToDatabase({ name });
   311→}
   312→
   313→function ContactForm() {
   314→  return (
   315→    <form action={submitForm}>
   316→      <input name="name" />
   317→      <button type="submit">Submit</button>
   318→    </form>
   319→  );
   320→}
   321→```
   322→
   323→### use() Hook
   324→
   325→```tsx
   326→import { use, Suspense } from "react";
   327→
   328→// Fetch data with Suspense
   329→function UserProfile({ userPromise }: { userPromise: Promise<User> }) {
   330→  const user = use(userPromise);
   331→  return <div>{user.name}</div>;
   332→}
   333→
   334→// Usage
   335→<Suspense fallback={<Loading />}>
   336→  <UserProfile userPromise={fetchUser(id)} />
   337→</Suspense>
   338→```
   339→
   340→### useTransition
   341→
   342→```tsx
   343→import { useState, useTransition } from "react";
   344→
   345→function SearchResults() {
   346→  const [query, setQuery] = useState("");
   347→  const [isPending, startTransition] = useTransition();
   348→
   349→  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
   350→    // Urgent update - input value
   351→    setQuery(e.target.value);
   352→
   353→    // Non-urgent update - search results
   354→    startTransition(() => {
   355→      // Expensive filtering/searching
   356→    });
   357→  };
   358→
   359→  return (
   360→    <div>
   361→      <input value={query} onChange={handleChange} />
   362→      {isPending && <Spinner />}
   363→      <Results query={query} />
   364→    </div>
   365→  );
   366→}
   367→```
