   369→---
   370→
   371→## Patterns
   372→
   373→### Compound Components
   374→
   375→```tsx
   376→// Parent provides context, children consume it
   377→const TabsContext = createContext<TabsContextType | null>(null);
   378→
   379→function Tabs({ children, defaultTab }: TabsProps) {
   380→  const [activeTab, setActiveTab] = useState(defaultTab);
   381→
   382→  return (
   383→    <TabsContext.Provider value={{ activeTab, setActiveTab }}>
   384→      <div className="tabs">{children}</div>
   385→    </TabsContext.Provider>
   386→  );
   387→}
   388→
   389→function TabList({ children }: { children: ReactNode }) {
   390→  return <div className="tab-list">{children}</div>;
   391→}
   392→
   393→function Tab({ id, children }: TabProps) {
   394→  const { activeTab, setActiveTab } = useContext(TabsContext)!;
   395→  return (
   396→    <button
   397→      className={activeTab === id ? "active" : ""}
   398→      onClick={() => setActiveTab(id)}
   399→    >
   400→      {children}
   401→    </button>
   402→  );
   403→}
   404→
   405→function TabPanel({ id, children }: TabPanelProps) {
   406→  const { activeTab } = useContext(TabsContext)!;
   407→  if (activeTab !== id) return null;
   408→  return <div className="tab-panel">{children}</div>;
   409→}
   410→
   411→// Usage
   412→<Tabs defaultTab="home">
   413→  <TabList>
   414→    <Tab id="home">Home</Tab>
   415→    <Tab id="about">About</Tab>
   416→  </TabList>
   417→  <TabPanel id="home">Home content</TabPanel>
   418→  <TabPanel id="about">About content</TabPanel>
   419→</Tabs>
   420→```
   421→
   422→### Render Props
   423→
   424→```tsx
   425→interface MousePosition {
   426→  x: number;
   427→  y: number;
   428→}
   429→
   430→interface MouseTrackerProps {
   431→  render: (position: MousePosition) => ReactNode;
   432→}
   433→
   434→function MouseTracker({ render }: MouseTrackerProps) {
   435→  const [position, setPosition] = useState({ x: 0, y: 0 });
   436→
   437→  const handleMouseMove = (e: React.MouseEvent) => {
   438→    setPosition({ x: e.clientX, y: e.clientY });
   439→  };
   440→
   441→  return (
   442→    <div onMouseMove={handleMouseMove} style={{ height: "100%" }}>
   443→      {render(position)}
   444→    </div>
   445→  );
   446→}
   447→
   448→// Usage
   449→<MouseTracker
   450→  render={({ x, y }) => (
   451→    <div>Mouse at: {x}, {y}</div>
   452→  )}
   453→/>
   454→```
   455→
   456→### Custom Hooks
   457→
   458→```tsx
   459→// Reusable logic extracted into hooks
   460→function useLocalStorage<T>(key: string, initialValue: T) {
   461→  const [storedValue, setStoredValue] = useState<T>(() => {
   462→    try {
   463→      const item = window.localStorage.getItem(key);
   464→      return item ? JSON.parse(item) : initialValue;
   465→    } catch {
   466→      return initialValue;
   467→    }
   468→  });
   469→
   470→  const setValue = (value: T | ((val: T) => T)) => {
   471→    try {
   472→      const valueToStore = value instanceof Function ? value(storedValue) : value;
   473→      setStoredValue(valueToStore);
   474→      window.localStorage.setItem(key, JSON.stringify(valueToStore));
   475→    } catch (error) {
   476→      console.error(error);
   477→    }
   478→  };
   479→
   480→  return [storedValue, setValue] as const;
   481→}
   482→
   483→// Usage
   484→const [theme, setTheme] = useLocalStorage("theme", "light");
   485→```
   486→
   487→---
   488→
   489→## Performance
   490→
   491→### React.memo
   492→
   493→```tsx
   494→import { memo } from "react";
   495→
   496→// Only re-renders if props change
   497→const ExpensiveComponent = memo(function ExpensiveComponent({ data }: Props) {
   498→  // Expensive render
   499→  return <div>{/* ... */}</div>;
   500→});
   501→
   502→// Custom comparison
   503→const ListItem = memo(
   504→  function ListItem({ item }: { item: Item }) {
   505→    return <div>{item.name}</div>;
   506→  },
   507→  (prevProps, nextProps) => prevProps.item.id === nextProps.item.id
   508→);
   509→```
   510→
   511→### Code Splitting
   512→
   513→```tsx
   514→import { lazy, Suspense } from "react";
   515→
   516→// Lazy load component
   517→const Dashboard = lazy(() => import("./Dashboard"));
   518→const Settings = lazy(() => import("./Settings"));
   519→
   520→function App() {
   521→  return (
   522→    <Suspense fallback={<Loading />}>
   523→      <Routes>
   524→        <Route path="/dashboard" element={<Dashboard />} />
   525→        <Route path="/settings" element={<Settings />} />
   526→      </Routes>
   527→    </Suspense>
   528→  );
   529→}
   530→```
   531→
   532→### Virtualization
   533→
   534→```tsx
   535→import { useVirtualizer } from "@tanstack/react-virtual";
   536→
   537→function VirtualList({ items }: { items: Item[] }) {
   538→  const parentRef = useRef<HTMLDivElement>(null);
   539→
   540→  const virtualizer = useVirtualizer({
   541→    count: items.length,
   542→    getScrollElement: () => parentRef.current,
   543→    estimateSize: () => 50,
   544→  });
   545→
   546→  return (
   547→    <div ref={parentRef} style={{ height: "400px", overflow: "auto" }}>
   548→      <div
   549→        style={{
   550→          height: `${virtualizer.getTotalSize()}px`,
   551→          position: "relative",
   552→        }}
   553→      >
   554→        {virtualizer.getVirtualItems().map(virtualRow => (
   555→          <div
   556→            key={virtualRow.key}
   557→            style={{
   558→              position: "absolute",
   559→              top: 0,
   560→              left: 0,
   561→              width: "100%",
   562→              height: `${virtualRow.size}px`,
   563→              transform: `translateY(${virtualRow.start}px)`,
   564→            }}
   565→          >
   566→            {items[virtualRow.index].name}
   567→          </div>
   568→        ))}
   569→      </div>
   570→    </div>
   571→  );
   572→}
   573→```
