# React

> A JavaScript library for building user interfaces with a component-based architecture.

---

## Overview

React is a declarative, component-based library for building UIs:
- **Component Model**: Encapsulated, reusable UI building blocks
- **Virtual DOM**: Efficient DOM updates through reconciliation
- **Unidirectional Data Flow**: Predictable state management
- **Hooks**: Function-based state and lifecycle management
- **Ecosystem**: Rich tooling and community support

---

## Why React

| Benefit | Description |
|---------|-------------|
| Component Reuse | Build once, use everywhere |
| Declarative | Describe UI, React handles updates |
| Learn Once | Write web, mobile (React Native), desktop |
| Large Ecosystem | Libraries for every need |
| Industry Standard | Most in-demand frontend skill |

---

## Core Concepts

### Components

```tsx
// Function component (modern standard)
interface UserCardProps {
  name: string;
  email: string;
  onSelect?: () => void;
}

export function UserCard({ name, email, onSelect }: UserCardProps) {
  return (
    <div className="user-card" onClick={onSelect}>
      <h3>{name}</h3>
      <p>{email}</p>
    </div>
  );
}

// Usage
<UserCard name="John" email="john@example.com" />
```

### JSX

```tsx
// JSX is JavaScript + XML syntax
const element = <h1>Hello, {user.name}!</h1>;

// Compiles to
const element = React.createElement('h1', null, `Hello, ${user.name}!`);

// Conditional rendering
{isLoggedIn && <WelcomeMessage />}
{isAdmin ? <AdminPanel /> : <UserPanel />}

// Lists with keys
{items.map(item => (
  <ListItem key={item.id} item={item} />
))}
```

---

## Hooks

### useState

```tsx
import { useState } from "react";

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(count + 1)}>+</button>
      <button onClick={() => setCount(c => c - 1)}>-</button>
    </div>
  );
}
```

### useEffect

```tsx
import { useEffect, useState } from "react";

function UserProfile({ userId }: { userId: string }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function fetchUser() {
      const response = await fetch(`/api/users/${userId}`);
      const data = await response.json();
      if (!cancelled) {
        setUser(data);
      }
    }

    fetchUser();

    // Cleanup function
    return () => {
      cancelled = true;
    };
  }, [userId]); // Dependency array

  if (!user) return <Loading />;
  return <div>{user.name}</div>;
}
```

### useCallback & useMemo

```tsx
import { useCallback, useMemo } from "react";

function ExpensiveList({ items, filter }: Props) {
  // Memoize expensive computation
  const filteredItems = useMemo(
    () => items.filter(item => item.name.includes(filter)),
    [items, filter]
  );

  // Memoize callback to prevent child re-renders
  const handleSelect = useCallback((id: string) => {
    console.log("Selected:", id);
  }, []);

  return (
    <ul>
      {filteredItems.map(item => (
        <ListItem
          key={item.id}
          item={item}
          onSelect={handleSelect}
        />
      ))}
    </ul>
  );
}
```

### useRef

```tsx
import { useRef, useEffect } from "react";

function TextInput() {
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Focus on mount
    inputRef.current?.focus();
  }, []);

  return <input ref={inputRef} type="text" />;
}

// Store mutable value without re-render
function Timer() {
  const intervalRef = useRef<number | null>(null);

  const start = () => {
    intervalRef.current = window.setInterval(() => {
      console.log("tick");
    }, 1000);
  };

  const stop = () => {
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
    }
  };

  return (
    <>
      <button onClick={start}>Start</button>
      <button onClick={stop}>Stop</button>
    </>
  );
}
```

### useContext

```tsx
import { createContext, useContext, useState, ReactNode } from "react";

// Create context
interface ThemeContextType {
  theme: "light" | "dark";
  toggle: () => void;
}

const ThemeContext = createContext<ThemeContextType | null>(null);

// Provider component
function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<"light" | "dark">("light");

  const toggle = () => setTheme(t => t === "light" ? "dark" : "light");

  return (
    <ThemeContext.Provider value={{ theme, toggle }}>
      {children}
    </ThemeContext.Provider>
  );
}

// Custom hook for consuming
function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within ThemeProvider");
  }
  return context;
}

// Usage
function ThemedButton() {
  const { theme, toggle } = useTheme();
  return (
    <button
      className={theme === "dark" ? "bg-black" : "bg-white"}
      onClick={toggle}
    >
      Toggle Theme
    </button>
  );
}
```

### useReducer

```tsx
import { useReducer } from "react";

interface State {
  count: number;
  error: string | null;
}

type Action =
  | { type: "increment" }
  | { type: "decrement" }
  | { type: "reset" }
  | { type: "error"; message: string };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "increment":
      return { ...state, count: state.count + 1, error: null };
    case "decrement":
      return { ...state, count: state.count - 1, error: null };
    case "reset":
      return { count: 0, error: null };
    case "error":
      return { ...state, error: action.message };
    default:
      return state;
  }
}

function Counter() {
  const [state, dispatch] = useReducer(reducer, { count: 0, error: null });

  return (
    <div>
      <p>Count: {state.count}</p>
      {state.error && <p className="error">{state.error}</p>}
      <button onClick={() => dispatch({ type: "increment" })}>+</button>
      <button onClick={() => dispatch({ type: "decrement" })}>-</button>
      <button onClick={() => dispatch({ type: "reset" })}>Reset</button>
    </div>
  );
}
```

